let TrusteePageVisits = 
    pageViews 
    | where timestamp {TimeRange} 
    | where url contains "/trustees" 
    | project operation_Id;
let FilterModifiedVisits = 
    customEvents 
    | where timestamp {TimeRange} 
    | where name == "Trustee District Filter Changed" 
    | where tostring(customDimensions.isDefault) != "true"
    | project operation_Id;
let TotalVisits = toscalar(TrusteePageVisits | count);
let ModifiedVisits = toscalar(
    FilterModifiedVisits 
    | join kind=inner TrusteePageVisits on operation_Id 
    | summarize by operation_Id 
    | count
);
print 
    TotalVisits = TotalVisits, 
    ModifiedVisits = ModifiedVisits, 
    ModificationRate = round(iif(TotalVisits > 0, todouble(ModifiedVisits) / todouble(TotalVisits) * 100, 0.0), 1)

