let CombinedEvents =
    customEvents
    | where timestamp {TimeRange}
    | where name == "Trustee Chapter Filter Changed"
    | extend chapterCount = toint(customMeasurements.selectedCount)
    | extend districtCount = toint(customMeasurements.districtCount)
    | where chapterCount > 0 and districtCount > 0
    | project operation_Id;
let CombinedVisits = toscalar(
    CombinedEvents
    | join kind=inner TrusteePageVisits on operation_Id
    | summarize by operation_Id
    | count
);
let TotalCombinedEvents = toscalar(CombinedEvents | count);
print
    TotalVisits = TotalVisits,
    CombinedVisits = CombinedVisits,
    PctCombinedVisits = round(iif(TotalVisits > 0, todouble(CombinedVisits) / todouble(TotalVisits) * 100, 0.0), 1),
    AvgCombinedEventsPerVisit = round(iif(TotalVisits > 0, todouble(TotalCombinedEvents) / todouble(TotalVisits), 0.0), 2)

